    24→const BP_OR = 20;
    25→const BP_AND = 30;
    26→const BP_EQUALITY = 40;
    27→const BP_COMPARISON = 50;
    28→const BP_ADDITIVE = 60;
    29→const BP_MULTIPLICATIVE = 70;
    30→const BP_UNARY = 90;
    31→const BP_POSTFIX = 100;
    32→
    33→function infixBP(type: TokenType): number {
    34→  switch (type) {
    35→    // EQ는 Pratt에서 처리하지 않음 → ExprStmt에서 할당으로 처리
    36→    case TokenType.OR: return BP_OR;
    37→    case TokenType.AND: return BP_AND;
    38→    case TokenType.EQEQ:
    39→    case TokenType.NEQ: return BP_EQUALITY;
    40→    case TokenType.LT:
    41→    case TokenType.GT:
    42→    case TokenType.LTEQ:
    43→    case TokenType.GTEQ: return BP_COMPARISON;
    44→    case TokenType.PLUS:
    45→    case TokenType.MINUS: return BP_ADDITIVE;
    46→    case TokenType.STAR:
    47→    case TokenType.SLASH:
    48→    case TokenType.PERCENT: return BP_MULTIPLICATIVE;
    49→    case TokenType.LPAREN:
    50→    case TokenType.LBRACKET:
    51→    case TokenType.DOT:
    52→    case TokenType.QUESTION: return BP_POSTFIX;
    53→    default: return 0;
    54→  }
    55→}
