    70→  parse(): { program: Program; errors: ParseError[] } {
    71→    const stmts: Stmt[] = [];
    72→    while (!this.isAtEnd()) {
    73→      try {
    74→        stmts.push(this.parseStmt());
    75→      } catch (e) {
    76→        // 에러 복구: 다음 문 시작까지 건너뜀
    77→        this.synchronize();
    78→      }
    79→    }
    80→    return { program: { stmts }, errors: this.errors };

